def get_market_write_lock(market_id: str) -> threading.Lock:
    """Serialize same-market journal appends so seq and prevEventHash cannot fork."""
    with _LOCK_REGISTRY_LOCK:
        lock = MARKET_WRITE_LOCKS.get(market_id)
        if lock is None:
            lock = threading.Lock()
            MARKET_WRITE_LOCKS[market_id] = lock
        return lock


def utc_timestamp() -> str:
    """Return the current UTC timestamp in ISO-8601 Zulu form."""
    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")


def register_stream_subscriber(
    registry: dict[str, set[Queue[dict[str, Any]]]],
    key: str,
) -> Queue[dict[str, Any]]:
    """Register one live stream subscriber queue for the requested key."""
    subscriber: Queue[dict[str, Any]] = Queue()
    with _STREAM_SUBSCRIBER_LOCK:
        subscribers = registry.get(key)
        if subscribers is None:
            subscribers = set()
            registry[key] = subscribers
        subscribers.add(subscriber)
    return subscriber


def unregister_stream_subscriber(
    registry: dict[str, set[Queue[dict[str, Any]]]],
    key: str,
    subscriber: Queue[dict[str, Any]],
) -> None:
    """Remove one subscriber queue from the live stream registry."""
    with _STREAM_SUBSCRIBER_LOCK:
        subscribers = registry.get(key)
        if subscribers is None:
            return
        subscribers.discard(subscriber)
        if not subscribers:
            registry.pop(key, None)


def publish_stream_message(
    registry: dict[str, set[Queue[dict[str, Any]]]],
    key: str,
    message: dict[str, Any],
) -> None:
    """Fan out one message to all subscribers for a registry key."""
    with _STREAM_SUBSCRIBER_LOCK:
        subscribers = list(registry.get(key, ()))

    for subscriber in subscribers:
        subscriber.put(deepcopy(message))


class ApiError(Exception):
    """Represent an API error with an HTTP status and structured payload."""

    def __init__(
        self,
        status: int,
        code: str,
        message: str,
        details: dict[str, Any] | None = None,
    ) -> None:
        """Initialize an API error for downstream HTTP serialization."""
        super().__init__(message)
        self.status = status
        self.code = code
        self.message = message
        self.details = details or {}


