def get_market_stream_replay_messages(market_id: str, from_seq: int, *, through_seq: int) -> list[dict[str, Any]]:
    """Build replay messages for historical market terminal events."""
    events = sorted(
        (
            deepcopy(event)
            for event in EVENTS.values()
            if str(event["marketId"]) == market_id and from_seq <= int(event["seq"]) <= through_seq
