        self.send_header("Connection", "keep-alive")
        self.send_header("X-Accel-Buffering", "no")
        self.end_headers()
        self.wfile.flush()

    def write_sse_message(self, message: dict[str, Any]) -> None:
        """Write and flush one SSE message to the client socket."""
        self.wfile.write(encode_sse_message(message))
        self.wfile.flush()

    def client_connection_closed(self) -> bool:
        """Best-effort check for a closed client socket without blocking."""
        try:
            data = self.connection.recv(
                1,
                getattr(socket, "MSG_PEEK", 0) | getattr(socket, "MSG_DONTWAIT", 0),
            )
        except (BlockingIOError, InterruptedError):
            return False
        except (AttributeError, OSError, ValueError):
            return True
        return data == b""

    def stream_messages(self, initial_messages: list[dict[str, Any]], subscriber: Queue[dict[str, Any]]) -> None:
        """Flush initial SSE messages, then fan out live queue updates."""
        self.send_sse_headers()
